diff --git a/include/CLI/Validators.hpp b/include/CLI/Validators.hpp
index c241387..4711539 100644
--- a/include/CLI/Validators.hpp
+++ b/include/CLI/Validators.hpp
@@ -262,6 +262,12 @@ class Range : public Validator {
             using CLI::detail::lexical_cast;
             T val;
             bool converted = lexical_cast(input, val);
+            if(converted && std::is_floating_point<T>::value) {
+                // Reject non-finite values (NaN, inf, -inf) explicitly
+                if(!std::isfinite(static_cast<double>(val))) {
+                    return std::string("Value ") + input + " is not a finite number (NaN or inf are not allowed)";
+                }
+            }
             if((!converted) || (val < min_val || val > max_val)) {
                 std::stringstream out;
                 out << "Value " << input << " not in range [";
                 out << min_val << " - " << max_val << "]";
                 return out.str();
             }
             return std::string{};
